SELECT mean
FROM monthly_data
WHERE metric_id = (SELECT metric_id FROM metrics WHERE metric_name = 'Sales');

SELECT mean
FROM monthly_data
WHERE metric_id = 0 AND month_id = 0;

SELECT mean
FROM monthly_data
WHERE month_id = 0;

SELECT AVG(mean) AS average_mean
FROM monthly_data
WHERE metric_id = (SELECT metric_id FROM metrics WHERE metric_name = 'Revenue');
